class Solution {
public:
    bool canConvertString(string s, string t, int k) {
        if (s.size() != t.size()) return false;
        int n = s.size();
        vector<int> diff(n);
        for (int i = 0; i < n; i++) {
            int d = abs(s[i] - t[i]);
            if (d > 0) {
                diff[i] = (d - 1) % 26 + 1;
            }
        }
        int maxDiff = 0;
        for (int d : diff) maxDiff += d;
        return maxDiff <= k;
    }
};
```

